        [Test]
        public void flow03CapNhatSoLuongGioHang()
        {
            // 1. Đăng nhập hệ thống
            driver.Navigate().GoToUrl("http://localhost:9025/");
            driver.FindElement(By.LinkText("Đăng nhập")).Click();
            driver.FindElement(By.Id("TenDangNhap")).SendKeys("huypham");
            driver.FindElement(By.Id("MatKhau")).SendKeys("123456");
            driver.FindElement(By.CssSelector(".btn")).Click();

            Thread.Sleep(2000); // Đợi chuyển hướng an toàn về trang chủ

            // 2. Thêm sản phẩm vào giỏ
            driver.FindElement(By.LinkText("Tất Cả Sản Phẩm")).Click();
            Thread.Sleep(1000);
            driver.FindElement(By.LinkText("Xem Chi Tiết")).Click();
            Thread.Sleep(1000);
            driver.FindElement(By.CssSelector(".btn-cta")).Click(); // Thêm vào giỏ hàng

            Thread.Sleep(1500); // Chờ hiệu ứng giỏ hàng cập nhật xong số lượng badge

            // 3. Vào trang giỏ hàng
            driver.FindElement(By.CssSelector(".cart-icon > .fas")).Click();
            Thread.Sleep(1500); // Đợi trang giỏ hàng load xong hoàn toàn diện mạo

            // Kiểm tra tổng tiền ban đầu (1 sản phẩm)
            Assert.That(driver.FindElement(By.CssSelector(".cart-total")).Text, Is.EqualTo("Tổng Cộng: 120.000 VNĐ"));

            // 4. Thay đổi số lượng sang 3
            var quantityInput = driver.FindElement(By.Name("quantity"));
            quantityInput.Click();

            // Sử dụng JavaScript để thay đổi giá trị trực tiếp, chặn đứng việc ô bị rỗng kích hoạt AJAX lỗi
            js.ExecuteScript("arguments[0].value = '3';", quantityInput);
            Thread.Sleep(500);

            // Gửi phím Enter ngay tại ô nhập liệu để Form tự submit cập nhật (Thay vì đi click lung tung trúng nút thanh toán)
            quantityInput.SendKeys(Keys.Enter);

            // Chờ 2 giây cố định để trang web xử lý tính toán lại tiền và render lại giao diện
            Thread.Sleep(2000);

            // 5. Xác nhận lại tổng tiền mới (3 sản phẩm)
            Assert.That(driver.FindElement(By.CssSelector(".cart-total")).Text, Is.EqualTo("Tổng Cộng: 360.000 VNĐ"));
        }

