        [Test]
        public void adminFlow15_XoaSanPhamVuaThem()
        {
            driver.Navigate().GoToUrl("http://localhost:9025/");
            driver.FindElement(By.LinkText("Đăng nhập")).Click();
            driver.FindElement(By.Id("TenDangNhap")).SendKeys("admin");
            driver.FindElement(By.Id("MatKhau")).SendKeys("123456");
            driver.FindElement(By.CssSelector(".btn")).Click();
            Thread.Sleep(2000);

            // Vào quản lý và thêm sản phẩm mới
            driver.FindElement(By.CssSelector(".user-menu-trigger")).Click();
            driver.FindElement(By.LinkText("Quản lý Sản Phẩm")).Click();
            Thread.Sleep(1500);
            driver.FindElement(By.LinkText("Thêm Sản Phẩm Mới")).Click();
            Thread.Sleep(1500);

            string tenBanhXoa = "TestXoaSP_" + new Random().Next(1000, 9999);
            driver.FindElement(By.Id("Name")).SendKeys(tenBanhXoa);
            driver.FindElement(By.Id("ImageUrl")).SendKeys("123");
            driver.FindElement(By.Id("Price")).SendKeys("120000");
            driver.FindElement(By.CssSelector(".btn")).Click();
            Thread.Sleep(2500); // Chờ lưu dữ liệu và điều hướng về bảng danh sách

            // Click nút xóa của sản phẩm vừa tạo trong bảng danh sách để nhảy sang trang xác nhận xóa
            var nutXoaCuaBanh = driver.FindElement(By.XPath($"//tr[contains(.,'{tenBanhXoa}')]//a[contains(@class,'btn-danger') or text()='Xóa']"));
            nutXoaCuaBanh.Click();
            Thread.Sleep(2000); // CHỜ ĐỢI: Trang xác nhận xóa (giống trong hình bạn gửi) load xong hoàn toàn
            Assert.That(driver.PageSource, Does.Contain("Bạn có chắc chắn muốn xóa sản phẩm này?"));

            // 2. Click vào nút "Xóa" màu đỏ trên trang (Thường là nút có class .btn-danger hoặc input loại submit)
            // Nếu Selector ".btn-danger" lỗi, bạn có thể đổi thành By.XPath("//input[@value='Xóa']") hoặc By.CssSelector("input.btn")
            driver.FindElement(By.CssSelector(".btn-danger")).Click();

            Thread.Sleep(2500); // Chờ xử lý xóa dưới SQL Server và quay về trang danh sách sản phẩm ban đầu

            // 3. Xác thực cuối cùng: Tên chiếc bánh đã chính thức bốc hơi khỏi danh sách
            Assert.That(driver.PageSource, Does.Not.Contain(tenBanhXoa));
        }

