        [Test]
        public void adminFlow19_QuanLyNhanVien_ThemVaSua()
        {
            driver.Navigate().GoToUrl("http://localhost:9025/");
            driver.FindElement(By.LinkText("Đăng nhập")).Click();
            driver.FindElement(By.Id("TenDangNhap")).SendKeys("admin");
            driver.FindElement(By.Id("MatKhau")).SendKeys("123456");
            driver.FindElement(By.CssSelector(".btn")).Click();
            Thread.Sleep(2000);

            driver.FindElement(By.CssSelector(".user-menu-trigger")).Click();
            driver.FindElement(By.LinkText("Quản lý Nhân Viên")).Click();
            Thread.Sleep(1500);

            driver.FindElement(By.LinkText("Tạo Nhân Viên Mới")).Click();
            Thread.Sleep(1500);

            // Tạo chuỗi ngẫu nhiên để gán cho Email và Tên Đăng Nhập tránh lỗi trùng dữ liệu
            int soNgauNhien = new Random().Next(1000, 9999);
            string tenNVMoi = "TestNV_" + soNgauNhien;
            string emailRandomMoi = "testnv_" + soNgauNhien + "@gmail.com";

            // 1. Kiểm tra Validation lỗi mật khẩu yếu (< 6 ký tự)
            driver.FindElement(By.Id("TenDangNhap")).SendKeys(tenNVMoi);
            driver.FindElement(By.Id("Email")).SendKeys(emailRandomMoi);
            driver.FindElement(By.Id("MatKhau")).SendKeys("123");
            driver.FindElement(By.CssSelector(".btn")).Click();
            Thread.Sleep(1000);

            Assert.That(driver.FindElement(By.CssSelector(".field-validation-error")).Text, Is.EqualTo("Mật khẩu phải có ít nhất 6 ký tự."));

            // 2. Sửa lại nhập đúng mật khẩu để tạo thành công
            var oPass = driver.FindElement(By.Id("MatKhau"));
            oPass.Clear();
            oPass.SendKeys("123456");
            driver.FindElement(By.CssSelector(".btn")).Click();
            Thread.Sleep(2500); // Chờ DB lưu nhân viên mới và tự redirect về trang danh sách

            // 3. Tiến hành sửa Email của chính nhân viên vừa tạo (Dùng XPath định vị chính xác dòng)
            var nutSuaCuaNV = driver.FindElement(By.XPath($"//tr[contains(.,'{tenNVMoi}')]//a[contains(@class,'btn-warning') or text()='Sửa']"));
            nutSuaCuaNV.Click();
            Thread.Sleep(1500);

            var oEmail = driver.FindElement(By.Id("Email"));
            oEmail.Clear();
            string emailSuaNgauNhien = "update_" + soNgauNhien + "@gmail.com";
            oEmail.SendKeys(emailSuaNgauNhien);
            driver.FindElement(By.CssSelector(".btn")).Click();
            Thread.Sleep(2000);

            // 4. Đăng xuất admin, lấy tài khoản nhân viên mới tạo đăng nhập kiểm tra phân quyền
            driver.FindElement(By.CssSelector(".user-menu-trigger")).Click();
            driver.FindElement(By.LinkText("Đăng xuất")).Click();
            Thread.Sleep(1500);

            driver.FindElement(By.LinkText("Đăng nhập")).Click();
            driver.FindElement(By.Id("TenDangNhap")).SendKeys(tenNVMoi);
            driver.FindElement(By.Id("MatKhau")).SendKeys("123456");
            driver.FindElement(By.CssSelector(".btn")).Click();
            Thread.Sleep(2000);

            Assert.That(driver.FindElement(By.CssSelector(".user-menu-trigger")).Text, Is.EqualTo($"Chào, {tenNVMoi}!"));
        }

        [Test]
        public void adminFlow20_QuanLyNhanVien_Xoa()
        {
            // Luồng độc lập: Tạo ra một nhân viên rác rồi tự xóa chính nó để test không bị gãy data
            driver.Navigate().GoToUrl("http://localhost:9025/");
            driver.FindElement(By.LinkText("Đăng nhập")).Click();
            driver.FindElement(By.Id("TenDangNhap")).SendKeys("admin");
            driver.FindElement(By.Id("MatKhau")).SendKeys("123456");
            driver.FindElement(By.CssSelector(".btn")).Click();
            Thread.Sleep(2000);

            // 1. Tạo nhân viên mẫu để chuẩn bị xóa (Qua UI để né lỗi 404)
            driver.FindElement(By.CssSelector(".user-menu-trigger")).Click();
            driver.FindElement(By.LinkText("Quản lý Nhân Viên")).Click();
            Thread.Sleep(1500);
            driver.FindElement(By.LinkText("Tạo Nhân Viên Mới")).Click();
            Thread.Sleep(1500);

            int maNgauNhien = new Random().Next(1000, 9999);
            string tenNVXoa = "TestDelete_" + maNgauNhien;
            string emailXoaRandom = "delete_" + maNgauNhien + "@gmail.com";

            driver.FindElement(By.Id("TenDangNhap")).SendKeys(tenNVXoa);
            driver.FindElement(By.Id("MatKhau")).SendKeys("123456");
            driver.FindElement(By.Id("Email")).SendKeys(emailXoaRandom);
            driver.FindElement(By.CssSelector(".btn")).Click();
            Thread.Sleep(2500); // Chờ server xử lý lưu và quay về trang danh sách

            // 2. Tìm đúng dòng của nhân viên có tên 'tenNVXoa' để nhấn nút xóa dữ liệu
            var nutXoaNhanVien = driver.FindElement(By.XPath($"//tr[contains(.,'{tenNVXoa}')]//a[contains(@class,'btn-danger') or text()='Xóa']"));
            nutXoaNhanVien.Click();
            Thread.Sleep(2000); // CHỜ ĐỢI: Trang xác nhận xóa (giống trong hình bạn gửi) load xong hẳn

            // =================================================================
            // ĐÃ SỬA: KIỂM TRA TEXT TRÊN BODY VÀ CLICK NÚT XÓA MÀU ĐỎ CỦA FORM
            // =================================================================

            // 1. Xác nhận dòng chữ hỏi xuất hiện trên trang View Delete Nhân Viên
            Assert.That(driver.PageSource, Does.Contain("Bạn có chắc chắn muốn xóa nhân viên này?"));

            // 2. Click vào nút "Xóa" màu đỏ trên giao diện (sử dụng class .btn-danger của Bootstrap)
            driver.FindElement(By.CssSelector(".btn-danger")).Click();

            Thread.Sleep(2500); // Chờ xử lý xóa dưới SQL và quay về trang danh sách ban đầu

            // 3. Xác thực cuối cùng: Tên nhân viên đã không còn tồn tại trong danh sách hiển thị
            Assert.That(driver.PageSource, Does.Not.Contain(tenNVXoa));
        }
    }
